    value: float = None
    op: str = None
    left: 'ASTNode' = None
    right: 'ASTNode' = None
    operand: 'ASTNode' = None


class Tokenizer:
    """Tokenizes a mathematical expression string."""

    def __init__(self, expression: str):
        self.expression = expression
        self.pos = 0
        self.tokens = []
        self._tokenize()

    def _tokenize(self):
        """Convert the expression string into a list of tokens."""
        while self.pos < len(self.expression):
            char = self.expression[self.pos]

            if char.isspace():
                self.pos += 1
                continue

            if char.isdigit() or char == '.':
                self._read_number()
            elif char in '+-*/()':
                self.tokens.append(('OP', char))
                self.pos += 1
            else:
                raise ValueError(f"Invalid character: {char}")

        # Add EOF marker
        self.tokens.append(('EOF', None))

    def _read_number(self):
        """Read a number (integer or decimal) from the expression."""
        start = self.pos
        has_dot = False

        while self.pos < len(self.expression):
            char = self.expression[self.pos]
            if char.isdigit():
                self.pos += 1
            elif char == '.' and not has_dot:
                has_dot = True
                self.pos += 1
            else:
                break

        if self.expression[start] == '.' and self.pos == start + 1:
            raise ValueError("Invalid number: '.' without digits")

        value = float(self.expression[start:self.pos])
        self.tokens.append(('NUMBER', value))

    def peek(self):
        """Return the current token without consuming it."""
        if self.pos < len(self.tokens):
            return self.tokens[self.pos]
        return ('EOF', None)

    def consume(self):
        """Consume and return the current token."""
        token = self.peek()
        self.pos += 1
        return token


class Parser:
    """Recursive descent parser for mathematical expressions."""

