        has_dot = False

        while self.char_pos < len(self.expression):
            char = self.expression[self.char_pos]
            if char.isdigit():
                self.char_pos += 1
            elif char == '.' and not has_dot:
                has_dot = True
                self.char_pos += 1
            else:
                break

        if self.expression[start] == '.' and self.char_pos == start + 1:
            raise ValueError("Invalid number: '.' without digits")

        value = float(self.expression[start:self.char_pos])
        self.tokens.append(('NUMBER', value))

    def peek(self):
        """Return the current token without consuming it."""
        if self.token_pos < len(self.tokens):
            return self.tokens[self.token_pos]
        return ('EOF', None)

    def consume(self):
        """Consume and return the current token."""
        token = self.peek()
        self.token_pos += 1
        return token

