class Parser:
    """Recursive descent parser for mathematical expressions."""

    def __init__(self, expression: str):
        self.tokenizer = Tokenizer(expression)
        self.current_token = self.tokenizer.consume()

    def parse(self) -> ASTNode:
        """Parse the expression and return the AST root node."""
        if self.current_token[0] == 'EOF':
            raise ValueError("Empty expression")

        ast = self._parse_expression()

        if self.current_token[0] != 'EOF':
            raise ValueError(f"Unexpected token: {self.current_token[1]}")

        return ast

    def _parse_expression(self) -> ASTNode:
        """Parse addition and subtraction (lowest precedence)."""
        node = self._parse_term()

        while self.current_token[0] == 'OP' and self.current_token[1] in ('+', '-'):
            op = self.current_token[1]
            self.current_token = self.tokenizer.consume()
            right = self._parse_term()
            node = ASTNode(type='binop', op=op, left=node, right=right)

        return node

    def _parse_term(self) -> ASTNode:
        """Parse multiplication and division (higher precedence)."""
        node = self._parse_unary()

        while self.current_token[0] == 'OP' and self.current_token[1] in ('*', '/'):
            op = self.current_token[1]
            self.current_token = self.tokenizer.consume()
            right = self._parse_unary()
            node = ASTNode(type='binop', op=op, left=node, right=right)

        return node

    def _parse_unary(self) -> ASTNode:
        """Parse unary minus."""
        if self.current_token[0] == 'OP' and self.current_token[1] == '-':
            self.current_token = self.tokenizer.consume()
            operand = self._parse_unary()
            return ASTNode(type='unary', op='-', operand=operand)

        return self._parse_primary()

    def _parse_primary(self) -> ASTNode:
        """Parse numbers and parenthesized expressions (highest precedence)."""
        token = self.current_token

        if token[0] == 'NUMBER':
            self.current_token = self.tokenizer.consume()
            return ASTNode(type='number', value=token[1])

        if token[0] == 'OP' and token[1] == '(':
            self.current_token = self.tokenizer.consume()
            node = self._parse_expression()

            if self.current_token[0] != 'OP' or self.current_token[1] != ')':
                raise ValueError("Unmatched parenthesis")

            self.current_token = self.tokenizer.consume()
            return node

        if token[0] == 'OP' and token[1] == ')':
            raise ValueError("Unmatched parenthesis")

        if token[0] == 'OP':
            raise ValueError(f"Unexpected operator: {token[1]}")

        raise ValueError(f"Unexpected token: {token}")


def parse(expression: str) -> ASTNode:
    """
    Parse a mathematical expression string into an ASTNode.

    Args:
        expression: A string containing a mathematical expression.

    Returns:
        ASTNode representing the parsed expression.

    Raises:
        ValueError: If the expression is invalid.
    """
    if not expression or not expression.strip():
        raise ValueError("Empty expression")

    parser = Parser(expression)
    return parser.parse()


def evaluate(node: ASTNode) -> float:
    """
    Evaluate an ASTNode and return the numeric result.

    Args:
        node: The root ASTNode to evaluate.

    Returns:
        The numeric result of the evaluation.

    Raises:
        ZeroDivisionError: If division by zero is encountered.
    """
    if node.type == 'number':
        return node.value

    if node.type == 'unary':
        operand_value = evaluate(node.operand)
        if node.op == '-':
            return -operand_value
        raise ValueError(f"Unknown unary operator: {node.op}")

    if node.type == 'binop':
        left_value = evaluate(node.left)
        right_value = evaluate(node.right)

        if node.op == '+':
            return left_value + right_value
        elif node.op == '-':
            return left_value - right_value
        elif node.op == '*':
            return left_value * right_value
        elif node.op == '/':
            if right_value == 0:
                raise ZeroDivisionError("Division by zero")
            return left_value / right_value
        else:
            raise ValueError(f"Unknown operator: {node.op}")

    raise ValueError(f"Unknown node type: {node.type}")
